external_knowledge:
- "performance" refers to the metric value obtained from benchmark tests; 
- "tested more than a handful of times" implies a count over 5 benchmark results;
- "slickest" and "less impressive" are metaphors referring to higher and lower average performance values, respectively.

sql:
SELECT 
    (SELECT COUNT(DISTINCT tag) FROM benchmark_tags) AS num_tags,
    (SELECT AVG(value) FROM benchmark_results) AS avg_value;

SELECT * 
FROM benchmark_results 
ORDER BY peak_value DESC;

SELECT COUNT(DISTINCT unit) AS total_distinct_units
FROM benchmark_results
WHERE value > 1;

SELECT name, manufacturer, release_date
FROM hardware_components
WHERE strftime('%Y', release_date) > '2000';

SELECT DISTINCT category 
FROM performance_metrics 
WHERE metric_type = 'integer';

